        let path_hits = deep_search(
            &case_path,
            DeepSearchOptions {
                category: None,
                file_types: None,
                query: "history.txt".to_string(),
                evidence_id: Some(evidence_id),
                include_content: false,
                max_results: 10,
                max_file_bytes: 64 * 1024,
            },
        )?;
